css_document:
:root{
  --red:
#ff0000; --red-dark:
#cc0000; --red-glow:rgba(255,0,0,.08);
  --surface:
#f5f5f5; --border:
#e0e0e0; --text:#111; --muted:#666;
}
.bragis-grid{ display:grid; grid-template-columns:repeat(auto-fill,minmax(280px,1fr)); gap:20px; }
.card{
  background:var(--surface); border:1px solid var(--border); border-radius:8px;
  overflow:hidden; cursor:pointer; transition:border-color .2s, box-shadow .2s;
}
.card:hover{ border-color:var(--red); box-shadow:0 0 20px var(--red-glow); }
.card-image{
  height:120px; background:linear-gradient(135deg,
#ececec,
#e0e0e0);
  display:flex; align-items:center; justify-content:center; position:relative; overflow:hidden;
}
.card-image::after{ content:''; position:absolute; bottom:0; left:0; right:0; height:3px; background:var(--red); }
.card-image img.portal-img{ max-width:90%; max-height:90px; object-fit:contain; position:relative; z-index:1; }
.card-image .img-placeholder{ font-size:13px; color:#aaa; }
.card-meta{ padding:14px 16px 16px; }
.card-title{
  font-family:'Barlow Condensed',sans-serif; font-size:17px; font-weight:700;
  letter-spacing:.06em; text-transform:uppercase; color:var(--text);
}
.card-links{ display:flex; flex-wrap:wrap; gap:6px; }
.card-links a,
.card-links .card-link-info{
  display:inline-block; padding:5px 12px; border-radius:4px; font-size:12px; font-weight:500;
  letter-spacing:.04em; text-decoration:none; border:1px solid var(--border);
  color:var(--muted); transition:background .15s,color .15s,border-color .15s;
}
.card-links a:hover,
.card-links .card-link-info:hover{ background:var(--red); color:#fff; border-color:var(--red); }

/* Info-knop gedraagt zich als een link-knop: reset de button-defaults */
.card-links .card-link-info{
  background:none;              /* button heeft standaard een grijze achtergrond */
  font-family:inherit;         /* button erft het lettertype niet vanzelf */
  line-height:normal;
  cursor:pointer;
}

/* Extra informatie — zichtbaar voor iedereen */
.extra-info{ margin-top:16px; font-size:14px; line-height:1.5; color:var(--text); }
.cred-list{ margin-top:16px; border-top:1px solid var(--border); padding-top:12px; }
.cred-row{ display:flex; gap:10px; font-size:13px; padding:4px 0; }
.cred-label{ flex:0 0 130px; color:var(--muted); font-weight:600; }
.cred-value{ flex:1; word-break:break-all; }
.modal-edit{ margin-top:14px; text-align:right; }
.modal-edit .edit-link{ font-size:12px; color:var(--muted); text-decoration:none; }
.modal-edit .edit-link:hover{ color:var(--red); }
/* "Portal toevoegen"-tegel */
.card-add{
  border:1px dashed #ccc; border-radius:8px; display:flex; flex-direction:column;
  align-items:center; justify-content:center; gap:8px; min-height:180px; cursor:pointer;
  text-decoration:none; color:#aaa; transition:border-color .2s, background .2s;
}
.card-add:hover{ border-color:var(--red); background:var(--red-glow); }
.card-add span{ font-size:28px; color:#bbb; line-height:1; }
.card-add p{ font-size:13px; font-weight:500; letter-spacing:.04em; text-transform:uppercase; }
